"use client";

import { useState, useEffect } from "react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import TodoItem from "@/components/TodoItem";
import { Todo, Priority } from "@/types/todo";
import { Plus } from "lucide-react";

const STORAGE_KEY = "todos";

type Filter = "all" | "active" | "completed";

const priorityOptions: { value: Priority; label: string }[] = [
  { value: "high", label: "높음" },
  { value: "medium", label: "중간" },
  { value: "low", label: "낮음" },
];

export default function TodoList() {
  const [todos, setTodos] = useState<Todo[]>([]);
  const [inputText, setInputText] = useState("");
  const [priority, setPriority] = useState<Priority>("medium");
  const [filter, setFilter] = useState<Filter>("all");

  // localStorage에서 불러오기
  useEffect(() => {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      const parsed = JSON.parse(stored) as (Omit<Todo, "createdAt"> & { createdAt: string })[];
      setTodos(parsed.map((t) => ({ ...t, createdAt: new Date(t.createdAt) })));
    }
  }, []);

  // localStorage에 저장
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(todos));
  }, [todos]);

  const addTodo = () => {
    const text = inputText.trim();
    if (!text) return;
    setTodos((prev) => [
      {
        id: crypto.randomUUID(),
        text,
        completed: false,
        priority,
        createdAt: new Date(),
      },
      ...prev,
    ]);
    setInputText("");
  };

  const toggleTodo = (id: string) => {
    setTodos((prev) =>
      prev.map((t) => (t.id === id ? { ...t, completed: !t.completed } : t))
    );
  };

  const deleteTodo = (id: string) => {
    setTodos((prev) => prev.filter((t) => t.id !== id));
  };

  const clearCompleted = () => {
    setTodos((prev) => prev.filter((t) => !t.completed));
  };

  const filtered = todos.filter((t) => {
    if (filter === "active") return !t.completed;
    if (filter === "completed") return t.completed;
    return true;
  });

  const activeCount = todos.filter((t) => !t.completed).length;

  return (
    <div className="w-full max-w-lg mx-auto space-y-4">
      {/* 입력 영역 */}
      <div className="flex gap-2">
        <Input
          placeholder="할 일을 입력하세요..."
          value={inputText}
          onChange={(e) => setInputText(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && addTodo()}
          className="flex-1"
        />
        <div className="flex gap-1">
          {priorityOptions.map((opt) => (
            <Button
              key={opt.value}
              variant={priority === opt.value ? "default" : "outline"}
              size="sm"
              onClick={() => setPriority(opt.value)}
            >
              {opt.label}
            </Button>
          ))}
        </div>
        <Button onClick={addTodo} size="icon">
          <Plus className="h-4 w-4" />
        </Button>
      </div>

      {/* 필터 */}
      <div className="flex items-center justify-between">
        <div className="flex gap-1">
          {(["all", "active", "completed"] as Filter[]).map((f) => (
            <Button
              key={f}
              variant={filter === f ? "secondary" : "ghost"}
              size="sm"
              onClick={() => setFilter(f)}
            >
              {f === "all" ? "전체" : f === "active" ? "진행중" : "완료"}
            </Button>
          ))}
        </div>
        <span className="text-sm text-muted-foreground">
          남은 항목: <Badge variant="secondary">{activeCount}</Badge>
        </span>
      </div>

      {/* 목록 */}
      <div className="space-y-2">
        {filtered.length === 0 ? (
          <p className="text-center text-muted-foreground py-8 text-sm">
            {filter === "completed" ? "완료된 항목이 없습니다." : "할 일이 없습니다."}
          </p>
        ) : (
          filtered.map((todo) => (
            <TodoItem
              key={todo.id}
              todo={todo}
              onToggle={toggleTodo}
              onDelete={deleteTodo}
            />
          ))
        )}
      </div>

      {/* 완료 항목 삭제 */}
      {todos.some((t) => t.completed) && (
        <div className="flex justify-end">
          <Button variant="ghost" size="sm" onClick={clearCompleted} className="text-muted-foreground">
            완료된 항목 삭제
          </Button>
        </div>
      )}
    </div>
  );
}