"use client";

import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Trash2 } from "lucide-react";
import { Todo, Priority } from "@/types/todo";

const priorityConfig: Record<Priority, { label: string; variant: "default" | "secondary" | "destructive" }> = {
  high: { label: "높음", variant: "destructive" },
  medium: { label: "중간", variant: "default" },
  low: { label: "낮음", variant: "secondary" },
};

interface TodoItemProps {
  todo: Todo;
  onToggle: (id: string) => void;
  onDelete: (id: string) => void;
}

export default function TodoItem({ todo, onToggle, onDelete }: TodoItemProps) {
  const { label, variant } = priorityConfig[todo.priority];

  return (
    <div className="flex items-center gap-3 p-3 rounded-lg border bg-card hover:bg-accent/50 transition-colors">
      <Checkbox
        checked={todo.completed}
        onCheckedChange={() => onToggle(todo.id)}
        id={todo.id}
      />
      <label
        htmlFor={todo.id}
        className={`flex-1 text-sm cursor-pointer ${todo.completed ? "line-through text-muted-foreground" : ""}`}
      >
        {todo.text}
      </label>
      <Badge variant={variant}>{label}</Badge>
      <Button
        variant="ghost"
        size="icon"
        className="h-7 w-7 text-muted-foreground hover:text-destructive"
        onClick={() => onDelete(todo.id)}
      >
        <Trash2 className="h-4 w-4" />
      </Button>
    </div>
  );
}
